INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('167d90f3-45b0-52c1-b383-0b4400a2097c', 'e484384e-e3e2-590c-8af1-36d54d28d850', 'في جملة «إنَّ العلمَ نورٌ»، ما إعراب «العلمَ»؟', '[{"id":"a","text":"اسم «إنّ» مرفوع بالضمّة"},{"id":"b","text":"مبتدأ مرفوع بالضمّة"},{"id":"c","text":"اسم «إنّ» منصوب بالفتحة"},{"id":"d","text":"خبر «إنّ» مرفوع بالضمّة"}]'::jsonb, 'c', '«إنّ» حرف ناسخ ينصب المبتدأ فيُسمّى اسمها، فـ«العلمَ» اسم إنّ منصوب وعلامة نصبه الفتحة.', 2)
