INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7837f880-8e56-54a1-846b-ae2d6aedf54e', 'e484384e-e3e2-590c-8af1-36d54d28d850', 'ما معنى الحرف الناسخ «كأنَّ»؟', '[{"id":"a","text":"التوكيد"},{"id":"b","text":"الاستدراك"},{"id":"c","text":"التمنّي"},{"id":"d","text":"التشبيه"}]'::jsonb, 'd', '«كأنّ» حرف ناسخ يفيد التشبيه، مثل: «كأنَّ وجهَهُ قمرٌ» أي هو مشبَّه بالقمر في الإضاءة.', 4)
