  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbb5adde-7969-5a81-8f34-47226c8cf51b', 'e484384e-e3e2-590c-8af1-36d54d28d850', 'في «ليسَ الكسلُ طريقَ النجاحِ»، ما إعراب «الكسلُ»؟', '[{"id":"a","text":"اسم «ليس» منصوب بالفتحة"},{"id":"b","text":"مبتدأ مرفوع"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"اسم «ليس» مرفوع بالضمّة"}]'::jsonb, 'd', '«ليس» فعل ناسخ جامد يرفع اسمه وينصب خبره، فـ«الكسلُ» اسم ليس مرفوع وعلامة رفعه الضمّة.', 5)
